import { useState, useEffect } from 'react';
import axios from 'axios';
import { InputSwitch } from 'primereact/inputswitch';
import { confirmDialog } from 'primereact/confirmdialog';

const API_BASE = 'http://localhost:8081/api/v1';

function Settings({ user, toast, onBack, onLogout }) {
  // Состояния для настроек
  const [pushNotifications, setPushNotifications] = useState(true);
  const [emailNotifications, setEmailNotifications] = useState(false);
  const [showFulfilledWishes, setShowFulfilledWishes] = useState(true);
  const [loading, setLoading] = useState(false);

  // Загружаем настройки пользователя при монтировании
  useEffect(() => {
    loadSettings();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const getAuthHeaders = () => {
    const token = localStorage.getItem('token');
    return token ? { Authorization: `Bearer ${token}` } : {};
  };

  const loadSettings = async () => {
    try {
      const response = await axios.get(`${API_BASE}/users/settings`, {
        headers: getAuthHeaders()
      });
      
      // Устанавливаем полученные настройки
      const settings = response.data;
      setPushNotifications(settings.pushNotifications ?? true);
      setEmailNotifications(settings.emailNotifications ?? false);
      setShowFulfilledWishes(settings.showFulfilledWishes ?? true);
    } catch (error) {
      console.error('Ошибка загрузки настроек:', error);
    }
  };

  const updateSettings = async (field, value) => {
    try {
      setLoading(true);
      await axios.patch(`${API_BASE}/users/settings`, 
        { [field]: value },
        { headers: getAuthHeaders() }
      );
      toast.current?.show({ 
        severity: 'success', 
        summary: 'Настройки обновлены', 
        life: 2000 
      });
    } catch (error) {
      toast.current?.show({ 
        severity: 'error', 
        summary: 'Ошибка обновления', 
        life: 2000 
      });
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteAccount = () => {
    confirmDialog({
      message: 'Вы уверены, что хотите удалить аккаунт? Это действие необратимо.',
      header: 'Удаление аккаунта',
      icon: 'pi pi-exclamation-triangle',
      acceptLabel: 'Да, удалить',
      rejectLabel: 'Отмена',
      acceptClassName: 'p-button-danger',
      accept: async () => {
        try {
          await axios.delete(`${API_BASE}/users/me`, {
            headers: getAuthHeaders()
          });
          toast.current?.show({ 
            severity: 'success', 
            summary: 'Аккаунт удален', 
            life: 2000 
          });
          setTimeout(() => {
            onLogout();
          }, 2000);
        } catch (error) {
          toast.current?.show({ 
            severity: 'error', 
            summary: 'Ошибка удаления', 
            life: 2000 
          });
        }
      }
    });
  };

  return (
    <div>
      {/* Хлебные крошки */}
      <div className="breadcrumbs" style={{ marginBottom: '20px' }}>
        <i className="pi pi-home" onClick={onBack} style={{ cursor: 'pointer' }}></i>
        <i className="pi pi-angle-right"></i>
        <span>Настройки</span>
      </div>

      {/* Заголовок Личные данные */}
      <h3 style={{ marginBottom: '16px', fontSize: '20px', fontWeight: '700', color: '#1e293b' }}>
        Личные данные
      </h3>

      {/* Карточка личных данных */}
      <div style={{ 
        background: 'white', 
        borderRadius: '25px', 
        padding: '32px',
        marginBottom: '20px'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          {/* Аватар */}
          <div style={{
            width: '80px',
            height: '80px',
            borderRadius: '50%',
            background: '#18B700',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            color: 'white',
            fontSize: '32px',
            fontWeight: '600',
            flexShrink: 0
          }}>
            {(user?.fullName?.charAt(0) || user?.username?.charAt(0) || user?.name?.charAt(0) || 'U').toUpperCase()}
          </div>

          {/* Информация */}
          <div style={{ flex: 1 }}>
            <h4 style={{ margin: '0 0 8px 0', fontSize: '18px', fontWeight: '600', color: '#1e293b' }}>
              {user?.fullName || user?.username || user?.name || 'Пользователь'}
            </h4>
            <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '4px' }}>
              <i className="pi pi-calendar" style={{ fontSize: '14px', color: '#18B700' }}></i>
              <span style={{ fontSize: '14px', color: '#18B700' }}>
                {user?.birthDate ? `${new Date(user.birthDate).toLocaleDateString('ru-RU', { day: 'numeric', month: 'long' })} (${Math.floor((new Date() - new Date(user.birthDate)) / (365.25 * 24 * 60 * 60 * 1000))} лет)` : 'Дата не указана'}
              </span>
            </div>
            <p style={{ margin: '0', fontSize: '14px', color: '#94a3b8' }}>
              {user?.bio || 'Личная информация отсутствует...'}
            </p>
          </div>

          {/* Кнопка редактирования */}
          <button style={{
            background: 'transparent',
            border: 'none',
            cursor: 'pointer',
            padding: '8px',
            flexShrink: 0
          }}>
            <i className="pi pi-pencil" style={{ fontSize: '20px', color: '#64748b' }}></i>
          </button>
        </div>
      </div>

      {/* Заголовок Настройки уведомлений */}
      <h3 style={{ marginBottom: '16px', fontSize: '20px', fontWeight: '700', color: '#1e293b' }}>
        Настройки уведомлений
      </h3>

      {/* Карточка настроек уведомлений */}
      <div style={{ 
        background: 'white', 
        borderRadius: '25px', 
        padding: '32px',
        marginBottom: '20px'
      }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
          {/* Push-уведомления */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
            <InputSwitch 
              checked={pushNotifications} 
              onChange={(e) => {
                setPushNotifications(e.value);
                updateSettings('pushNotifications', e.value);
              }}
              disabled={loading}
            />
            <span style={{ fontSize: '16px', color: '#64748b' }}>Push-уведомления</span>
          </div>

          {/* Email */}
          <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
            <InputSwitch 
              checked={emailNotifications} 
              onChange={(e) => {
                setEmailNotifications(e.value);
                updateSettings('emailNotifications', e.value);
              }}
              disabled={loading}
            />
            <span style={{ fontSize: '16px', color: '#64748b' }}>Email</span>
          </div>
        </div>
      </div>

      {/* Заголовок Исполненные желания */}
      <h3 style={{ marginBottom: '16px', fontSize: '20px', fontWeight: '700', color: '#1e293b' }}>
        Исполненные желания
      </h3>

      {/* Карточка исполненных желаний */}
      <div style={{ 
        background: 'white', 
        borderRadius: '25px', 
        padding: '32px',
        marginBottom: '20px'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
          <InputSwitch 
            checked={showFulfilledWishes} 
            onChange={(e) => {
              setShowFulfilledWishes(e.value);
              updateSettings('showFulfilledWishes', e.value);
            }}
            disabled={loading}
          />
          <span style={{ fontSize: '16px', color: '#64748b' }}>
            Отображать раздел "Исполненные желания" на моей странице
          </span>
        </div>
      </div>

      {/* Кнопки действий */}
      <div style={{ display: 'flex', gap: '16px', marginTop: '24px' }}>
        <button
          onClick={onLogout}
          style={{
              width: '200px',      
  height: '40px',      
  padding: '0',       
  fontSize: '16px',
            fontSize: '16px',
            fontWeight: '600',
            color: '#E26E63',
            
            border: '2px solid #E26E63',
            borderRadius: '8px',
            
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: '8px',
            cursor: 'pointer',  
          }}
         
        >
          <i className="pi pi-sign-out" style={{ color: 'white' }}></i>
          Выйти из аккаунта
        </button>
        <button
          onClick={handleDeleteAccount}
          style={{
              width: '200px',   
  height: '40px',      
  padding: '0',       
  fontSize: '16px',
            fontSize: '16px',
            fontWeight: '600',
            color: 'white',
            background: '#E26E63',
            border: '2px solid #E26E63',
            borderRadius: '8px',
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: '8px',
            transition: 'all 0.2s'
          }}
          onMouseEnter={(e) => e.currentTarget.style.background = '#dc2626'}
          onMouseLeave={(e) => e.currentTarget.style.background = '#E26E63'}
        >
          <i className="pi pi-trash"></i>
          Удалить аккаунт
        </button>
      </div>
    </div>
  );
}

export default Settings;
